INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00427', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲於生前作成遺囑，將自己所有之A屋遺贈於乙。嗣後，甲將A屋出售。甲死亡時，遺產僅有新 臺幣（下同）500萬元之存款。乙得否對甲之唯一繼承人丙請求相當於A屋之價值200萬元？', '["可，因丙應以遺產為限，對乙負清償責任", "可，遺贈因甲之死亡而生效", "不可，因甲出售A屋，視為撤回遺贈", "不可，因遺贈債務之給付不能係不可歸責於丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00428', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲乙為夫妻。有一子丙，一女丁。丙有戊、己、庚三子，丁有辛子。丁早逝。乙死亡時，下列敘 述，何者正確？', '["辛不得繼承", "辛得繼承乙五分之一的遺產", "辛得繼承乙四分之一的遺產", "辛得繼承乙三分之一的遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00429', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲男與乙女結婚，婚後生子丙。嗣後因甲男與乙女離婚，乙女再與丁女於戶政機關辦理結婚登記， 丁女依法收養丙男為養子，經過1年後，丁女死亡，其死亡前依法立有遺囑，將所有財產全數捐 贈社福團體。丁女死亡時，留有遺產新臺幣（下同）900 萬元，丁女有唯一親人戊妹。何人各有 特留分多少金額？', '["乙女、戊妹特留分各225萬元", "乙女、丙養子特留分各225萬元", "乙女、丙養子、戊妹特留分各150萬元", "乙女特留分225萬元、戊妹特留分150萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00430', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者得以事後拋棄？', '["親屬關係", "繼承權", "自由", "權利能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00431', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於法律行為之代理及代表之敘述，何者正確？', '["公司董事不問有無代表權，就其代表公司所為之任何法律行為，均屬有效", "甲請5歲兒童乙傳遞訊息，此兒童乙為甲之代理人", "占有輔助人為代理人之一種型態", "代理人不以有完全行為能力為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00432', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '於民國（下同）106年間，訂立租賃契約，約定：「租賃期間自107年6月1日起，租期2年」， 該租賃關係何時終了？', '["109年5月30日", "109年5月31日", "109年6月1日", "109年6月2日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00433', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於消滅時效與法律行為效力之敘述，何者錯誤？', '["民法第128條所稱之請求權可行使時，係指行使該請求權無障礙時而言，單純當事人主觀上不 知可行使權利，並非請求權可行使之障礙", "時效不完成係指一定行為之發生，將導致時效不完成，且嗣後將重新起算時效", "無權處分之效力未定，應以物權行為效力未定，債權行為應屬有效", "無權代理之效力未定，則無權代理所為之債權行為與物權行為均屬效力未定 20420 20520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00434', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於附條件之法律行為，下列敘述，何者錯誤？', '["附停止條件之法律行為，於條件成就時，當然發生效力", "附解除條件之法律行為，於條件成就時，不待當事人另以意思表示為終止，即失效力", "約定解除權之行使，須以意思表示為之者，與附解除條件相同", "因條件成就而受不利益之當事人，如以不正當行為阻其條件之成就者，視為條件已成就"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00435', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於不當得利之敘述，何者正確？', '["甲擅自使用乙所有，但長年閒置且無人居住之A屋，此時乙並未受有損害，故不構成不當得利", "甲誤認乙對第三人丙之新臺幣（下同）5萬元債務，為自己之債務，故向丙為5萬元之清償， 嗣後甲得向丙請求返還", "甲雖知自己對乙之10萬元債務尚未到清償期，但仍於清償期屆至前，將本金及利息如數給付。 甲於給付後隔日若突須用錢，均得向乙請求返還", "甲不知自己從乙處受領 10 顆蘋果乃無法律上之原因。若蘋果已全數食用完畢，則甲應對乙償 還其價額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00436', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲駕車超速致失控撞上路過之上班族乙，下列敘述，何者錯誤？', '["乙傷重不治時，乙之祖父丙得向甲請求非財產上損害賠償", "乙傷重不治時，乙之父丁得向甲請求非財產上損害賠償", "乙經入院治療1個月後，傷重不治時，為乙支出醫療費用之友人戊，得向甲請求損害賠償", "乙嗣後經判定為植物人狀態時，與乙感情深厚之母己基於身分法益受不法侵害而情節重大者， 得向甲請求非財產上損害賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
